#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <string>
#include <vector>
#include "cJSON.h"
#include "lodepng.h"

static std::string readFile(const char* path){
    FILE* f=fopen(path,"rb");
    if(!f){fprintf(stderr,"cannot open %s\n",path);exit(1);}
    fseek(f,0,SEEK_END);long n=ftell(f);fseek(f,0,SEEK_SET);
    std::string s;s.resize(n);
    if(fread(&s[0],1,n,f)!=(size_t)n){fclose(f);exit(1);}
    fclose(f);return s;
}

static std::vector<std::vector<double>> getMat(cJSON* root,const char* key){
    cJSON* a=cJSON_GetObjectItemCaseSensitive(root,key);
    std::vector<std::vector<double>> m;
    cJSON* row;
    cJSON_ArrayForEach(row,a){
        std::vector<double> r;
        cJSON* v;
        cJSON_ArrayForEach(v,row) r.push_back(v->valuedouble);
        m.push_back(r);
    }
    return m;
}
static std::vector<double> getVec(cJSON* root,const char* key){
    cJSON* a=cJSON_GetObjectItemCaseSensitive(root,key);
    std::vector<double> r;
    cJSON* v;
    cJSON_ArrayForEach(v,a) r.push_back(v->valuedouble);
    return r;
}

static std::vector<double> linear(const std::vector<double>& x,
        const std::vector<std::vector<double>>& w,const std::vector<double>& b,bool relu){
    std::vector<double> out(w.size());
    for(size_t i=0;i<w.size();++i){
        double s=b[i];
        for(size_t j=0;j<w[i].size();++j) s+=w[i][j]*x[j];
        if(relu&&s<0) s=0;
        out[i]=s;
    }
    return out;
}

int main(int argc,char** argv){
    if(argc<3){fprintf(stderr,"usage: %s weights.json image.png\n",argv[0]);return 1;}
    std::string js=readFile(argv[1]);
    cJSON* root=cJSON_Parse(js.c_str());
    if(!root){fprintf(stderr,"bad json\n");return 1;}
    auto iw=getMat(root,"input_layer.weight");
    auto ib=getVec(root,"input_layer.bias");
    auto hw=getMat(root,"hidden_layer.weight");
    auto hb=getVec(root,"hidden_layer.bias");
    auto ow=getMat(root,"output_layer.weight");
    auto ob=getVec(root,"output_layer.bias");

    std::vector<unsigned char> img;unsigned w,h;
    unsigned err=lodepng::decode(img,w,h,argv[2],LCT_GREY,8);
    if(err){fprintf(stderr,"png error %u\n",err);return 1;}
    std::vector<double> x(w*h);
    for(size_t i=0;i<x.size();++i) x[i]=img[i]/255.0;

    auto a=linear(x,iw,ib,true);
    a=linear(a,hw,hb,true);
    a=linear(a,ow,ob,false);
    int best=0;for(size_t i=1;i<a.size();++i) if(a[i]>a[best]) best=(int)i;
    printf("%d\n",best);
    cJSON_Delete(root);
    return 0;
}
